// ─── Stat block ──────────────────────────────────────────────────────────
function StatBlock({ value, suffix, label, delay }: { value: number; suffix: string; label: string; delay: number }) {
  const count = useCounter(value, 2000, delay);
  return (
    <div style={{ textAlign: 'center' }}>
      <div style={{
        fontFamily: "'Syne', sans-serif",
        fontWeight: 800,
        fontSize: 'clamp(1.5rem, 3vw, 2.2rem)',
        color: '#f59e0b',
        lineHeight: 1,
        letterSpacing: '-0.03em',
      }}>
        {count.toLocaleString()}{suffix}
      </div>
      <div style={{
        fontFamily: "'JetBrains Mono', monospace",
        fontSize: '9px',
        color: 'rgba(138,155,181,0.8)',
        textTransform: 'uppercase',
        letterSpacing: '0.12em',
        marginTop: '5px',
      }}>
        {label}
      </div>
    </div>
  );
}

// ─── Feature pill ─────────────────────────────────────────────────────────
function FeaturePill({ icon: Icon, text, delay }: { icon: React.ComponentType<{size?: number; style?: React.CSSProperties}>; text: string; delay: string }) {
