ALTER TABLE rams ALTER COLUMN method_statement TYPE text USING CASE WHEN method_statement::text = '[]' THEN '' ELSE method_statement::text END;
ALTER TABLE rams ALTER COLUMN ppe TYPE text USING CASE WHEN ppe::text = '[]' THEN '' ELSE ppe::text END;
ALTER TABLE rams ALTER COLUMN signatures TYPE text USING signatures::text;

-- equipment: add category, serial_number, ownership, inspection_due, mewp_check, project_id, supplier, notes
